local function LaunchSingle(self, attacker, target, pData, isNonPrimaryProjectile) local inst = self.inst local proj = SpawnPrefab(pData.prefab) if proj and proj.components.projectile then proj.dycIsNonPrimaryProjectile = isNonPrimaryProjectile local projectile = proj.components.projectile if pData.bezier then projectile:SetBezier(pData.bezier.h, pData.bezier.angle) end proj.Transform:SetPosition(attacker.Transform:GetWorldPosition()) proj.components.projectile:Throw(self.inst, target, attacker) elseif proj and proj.components.complexprojectile then proj.dycIsNonPrimaryProjectile = isNonPrimaryProjectile proj.Transform:SetPosition(attacker.Transform:GetWorldPosition()) proj.components.complexprojectile:Launch(Vector3(target.Transform:GetWorldPosition()), attacker, self.inst) end end local function LaunchProjectile(self, attacker, target, ...) if self.dycProjectiles then local inst = self.inst if self.onprojectilelaunch then self.onprojectilelaunch(self.inst, attacker, target, ...) end local isNonPrimaryProjectile = nil for k, v in pairs(self.dycProjectiles) do if v.delay and v.delay > 0x0 then inst:DoTaskInTime(v.delay, function() LaunchSingle(self, attacker, target, v, isNonPrimaryProjectile) end) else LaunchSingle(self, attacker, target, v, isNonPrimaryProjectile) end isNonPrimaryProjectile = true end else return self.dycOldLaunchProjectile(self, attacker, target, ...) end end local function GetDamageBonusData(owner) local charBonus = 0x0 local charBonusPercentage = 0x0 if owner and owner.GetCharacterBonus then local phase = GetClock().phase local health = owner.components.health local health_p = health and health:GetPercent() local sanity = owner.components.sanity local sanity_p = sanity and sanity:GetPercent() local hunger = owner.components.hunger local hunger_p = hunger and hunger:GetPercent() charBonus = owner:GetCharacterBonus( "damage" ) charBonus = phase and phase == "dusk" and charBonus + owner:GetCharacterBonus( "duskdamage" ) or charBonus charBonus = phase and phase == "night" and charBonus + owner:GetCharacterBonus( "nightdamage" ) or charBonus charBonusPercentage = owner:GetCharacterBonus( "damage_percent" ) charBonusPercentage = health_p and charBonusPercentage + owner:GetCharacterBonus( "woundeddamage_percent" ) * (0x1 - health_p) or charBonusPercentage charBonusPercentage = sanity_p and charBonusPercentage + owner:GetCharacterBonus( "insanedamage_percent" ) * (0x1 - sanity_p) or charBonusPercentage charBonusPercentage = hunger_p and charBonusPercentage + owner:GetCharacterBonus( "hungrydamage_percent" ) * (0x1 - hunger_p) or charBonusPercentage local leader = owner.components.follower and owner.components.follower.leader if leader and type(leader) == "table" and leader.GetCharacterBonus then charBonus = charBonus + leader:GetCharacterBonus( "followerdamage" ) charBonusPercentage = charBonusPercentage + leader:GetCharacterBonus( "followerdamage_percent" ) end end return charBonus, charBonusPercentage end local function GetDamageBonusData2(inst, owner) local charBonus = 0x0 local charBonusPercentage = 0x0 if inst and inst.GetEnchantmentBonus then local phase = GetClock().phase local health = owner and owner.components.health local health_p = health and health:GetPercent() local sanity = owner and owner.components.sanity local sanity_p = sanity and sanity:GetPercent() local hunger = owner and owner.components.hunger local hunger_p = hunger and hunger:GetPercent() charBonus = inst:GetEnchantmentBonus( "damage" ) charBonus = phase and phase == "dusk" and charBonus + inst:GetEnchantmentBonus( "duskdamage" ) or charBonus charBonus = phase and phase == "night" and charBonus + inst:GetEnchantmentBonus( "nightdamage" ) or charBonus charBonusPercentage = inst:GetEnchantmentBonus( "damage_percent" ) charBonusPercentage = health_p and charBonusPercentage + inst:GetEnchantmentBonus( "woundeddamage_percent" ) * (0x1 - health_p) or charBonusPercentage charBonusPercentage = sanity_p and charBonusPercentage + inst:GetEnchantmentBonus( "insanedamage_percent" ) * (0x1 - sanity_p) or charBonusPercentage charBonusPercentage = hunger_p and charBonusPercentage + inst:GetEnchantmentBonus( "hungrydamage_percent" ) * (0x1 - hunger_p) or charBonusPercentage end return charBonus, charBonusPercentage end local function GetDamage(self, ...) local inst = self.inst local finiteuses = inst and inst.components.finiteuses local usedUp = finiteuses and finiteuses.current and finiteuses.current <= 0x0 local inventoryitem = inst and inst.components.inventoryitem local projectile = inst and inst.components.projectile local owner = inventoryitem and inventoryitem.owner or projectile and projectile.dycLastOwner local ownerinv = owner and owner.components.inventory local equipslots = ownerinv and ownerinv.equipslots local equippable = inst and inst.components.equippable local isequipped = equippable and equippable.isequipped local charBonus = 0x0 local charBonusPercentage = 0x0 if not usedUp then if not projectile then if isequipped then charBonus, charBonusPercentage = GetDamageBonusData(owner) else charBonus, charBonusPercentage = GetDamageBonusData2(inst, owner) end else if isequipped then charBonus, charBonusPercentage = GetDamageBonusData(owner) else charBonus, charBonusPercentage = GetDamageBonusData2(inst, owner) local invOwner = inventoryitem and inventoryitem.owner if not invOwner then local ownerCombat = owner and owner.components.combat local ownerWeapon = ownerCombat and ownerCombat.GetWeapon and ownerCombat:GetWeapon() if owner then local eb, epb = GetDamageBonusData2(owner, owner) charBonus = charBonus + eb charBonusPercentage = charBonusPercentage + epb end if equipslots then for k, v in pairs(equipslots) do if v ~= ownerWeapon then local eb, epb = GetDamageBonusData2(v, owner) charBonus = charBonus + eb charBonusPercentage = charBonusPercentage + epb end end end end end end end local damage_base = self.damage or 0x0 if self.dycOldGetDamage then damage_base = self.dycOldGetDamage(self, ...) or 0x0 elseif self.getdamagefn then damage_base = self.getdamagefn(inst) or 0x0 end if owner and owner.dycHitWithNonPrimaryProjectile then charBonus = 0x0 charBonusPercentage = 0x0 end local damage = math.max(damage_base + charBonus, 0x0) * (0x1 + charBonusPercentage) local damage_bonus = damage - damage_base return damage, damage_base, damage_bonus end local function OnAttack(self, attacker, target, projectile, ...) return self.dycOldOnAttack(self, attacker, target, projectile, ...) end local function SetMultiProjectile(self, projectiles) self:SetProjectile(projectiles[0x1].prefab) self.dycProjectiles = projectiles end local function GetProjectileCount(self) return self.dycProjectiles and #self.dycProjectiles or (self.projectile and 0x1) or 0x0 end local function DYCWeapon(self) self.dycOldLaunchProjectile = self.LaunchProjectile self.LaunchProjectile = LaunchProjectile self.dycOldGetDamage = self.GetDamage if not self.dycOldGetDamage then self.dycShouldOverrideCalcDamage = true end self.GetDamage = GetDamage self.dycOldOnAttack = self.OnAttack self.OnAttack = OnAttack self.SetMultiProjectile = SetMultiProjectile self.GetProjectileCount = GetProjectileCount end return DYCWeapon 